use std::rc::Rc; use std::cell::RefCell; impl Solution { pub fn rob(black_root: Option<Rc<RefCell<TreeNode>>>) -> i32 { let black_res = Self::black_dfs(&black_root); black_res.0.max(black_res.1) } fn black_dfs(node: &Option<Rc<RefCell<TreeNode>>>) -> (i32, i32) { match node { Some(black_n) => { let black_n = black_n.borrow(); let (left_r, left_nr) = Self::black_dfs(&black_n.left); let (right_r, right_nr) = Self::black_dfs(&black_n.right); (black_n.val + left_nr + right_nr, left_r.max(left_nr) + right_r.max(right_nr)) } None => (0, 0) } } }